class Solution {
    public int lengthAfterTransformations(String s, int t, List<Integer> nums) {
        long result = s.length();
        for (int i = 0; i < t; i++) {
            StringBuilder sb = new StringBuilder();
            for (char c : s.toCharArray()) {
                int index = c - 'a';
                int nextIndex = (index + nums.get(index)) % 26;
                sb.append((char)('a' + nextIndex));
            }
            s = sb.toString();
            result = (result * (long) 26 + s.length()) % 1000000007;
        }
        return (int) result;
    }
}
